import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Avatar, Badge, icon } from 'decantr/components';

code.example:
function StorefrontHero({ creator, onSubscribe }) {
  const { div, h1, p, span, a, img } = tags;

  const socials = creator.socials || [];
  const socialIcons = { twitter: 'twitter', instagram: 'instagram', youtube: 'youtube', tiktok: 'music-2', website: 'globe' };

  return div({ class: css('_flex _col') },
    div({ class: css('_relative _h[240px] _md:h[320px] _overflow[hidden]') },
      creator.coverImage
        ? img({ src: creator.coverImage, class: css('_wfull _hfull _objcover') })
        : div({ class: css('_wfull _hfull _bgGradient _from[#F97316] _to[#8B5CF6]') }),
      div({ class: css('_absolute _inset0 _bg[linear-gradient(transparent_60%,rgba(0,0,0,0.5))]') })
    ),
    div({ class: css('_relative _px6 _md:px12 _pb8') },
      div({ class: css('_flex _col _md:row _aic _md:aie _gap6 _-mt16') },
        Avatar({
          src: creator.avatar,
          name: creator.name,
          size: 'xl',
          class: css('_w32 _h32 _ring4 _ringbg _shadow')
        }),
        div({ class: css('_flex1 _tc _md:tl') },
          div({ class: css('_flex _aic _jcc _md:jcs _gap2 _mb2') },
            h1({ class: css('_heading2') }, creator.name),
            creator.verified ? Badge({ variant: 'default', class: css('_bgPrimary') },
              icon('check', { size: '12' })
            ) : null
          ),
          p({ class: css('_fgmuted _mb4 _maxw[600px]') }, creator.tagline),
          div({ class: css('_flex _aic _jcc _md:jcs _gap4 _mb4 _flexwrap') },
            div({ class: css('_flex _aic _gap1') },
              icon('users', { size: '16', class: css('_fgmuted') }),
              span({ class: css('_fontmedium') }, creator.subscriberCount?.toLocaleString() || 0),
              span({ class: css('_fgmuted') }, ' subscribers')
            ),
            div({ class: css('_flex _aic _gap1') },
              icon('file-text', { size: '16', class: css('_fgmuted') }),
              span({ class: css('_fontmedium') }, creator.postCount || 0),
              span({ class: css('_fgmuted') }, ' posts')
            )
          ),
          socials.length > 0 ? div({ class: css('_flex _aic _jcc _md:jcs _gap3') },
            ...socials.map(s =>
              a({ href: s.url, target: '_blank', class: css('_w8 _h8 _r[50%] _bgmuted/10 _flex _center _trans _hover:bgmuted/20') },
                icon(socialIcons[s.platform] || 'link', { size: '16', class: css('_fgmuted') })
              )
            )
          ) : null
        ),
        div({ class: css('_flex _gap2') },
          Button({ variant: 'outline', size: 'lg' },
            icon('share-2', { size: '18' })
          ),
          Button({ variant: 'primary', size: 'lg', class: css('studio-glow'), onclick: onSubscribe },
            'Subscribe'
          )
        )
      )
    )
  );
}

