function MinimalStorefrontHero({ creator, onSubscribe }) {
  const { div, span } = tags;

  return div({ class: css('_flex _aic _gap4 _p4 _borderB') },
    Avatar({ src: creator.avatar, name: creator.name, size: 'md' }),
    div({ class: css('_flex1') },
      span({ class: css('_fontmedium') }, creator.name),
      div({ class: css('_textsm _fgmuted') }, creator.subscriberCount, ' subscribers')
    ),
    Button({ variant: 'primary', onclick: onSubscribe }, 'Subscribe')
  );
}

