function VideoStorefrontHero({ creator, onSubscribe }) {
  const { div, h1, p, video } = tags;

  return div({ class: css('_relative _h[400px] _overflow[hidden]') },
    video({
      src: creator.backgroundVideo,
      autoplay: true,
      loop: true,
      muted: true,
      class: css('_absolute _inset0 _wfull _hfull _objcover')
    }),
    div({ class: css('_absolute _inset0 _bg[rgba(0,0,0,0.5)]') }),
    div({ class: css('_absolute _inset0 _flex _col _center _tc _p6') },
      Avatar({ src: creator.avatar, name: creator.name, size: 'xl', class: css('_mb4 _ring4 _ring[white/20]') }),
      h1({ class: css('_heading2 _text[white] _mb2') }, creator.name),
      p({ class: css('_text[white/80] _mb6 _maxw[500px]') }, creator.tagline),
      Button({ variant: 'primary', size: 'lg', onclick: onSubscribe }, 'Subscribe Now')
    )
  );
}

